import threading

class Singleton:
    """Thread-safe Singleton implementation using double-checked locking."""
    _instance = None
    _lock = threading.Lock()

    def __new__(cls):
        """Create a new instance or return the existing one."""
        if cls._instance is None:
            with cls._lock:
                if cls._instance is None:
                    cls._instance = super().__new__(cls)
        return cls._instance

    def __init__(self):
        """Initialize the singleton instance (only once)."""
        if not hasattr(self, '_initialized'):
            self._initialized = True
            self.value = "Singleton Value"

    def get_value(self):
        """Get the singleton's value."""
        return self.value

    def set_value(self, value):
        """Set the singleton's value."""
        self.value = value


def get_singleton_instance():
    """Retrieve the singleton instance."""
    return Singleton()


# Example usage
if __name__ == "__main__":
    singleton1 = get_singleton_instance()
    singleton2 = get_singleton_instance()

    print(singleton1 is singleton2)  # Output: True
    print(singleton1.get_value())    # Output: "Singleton Value"

    singleton1.set_value("New Value")
    print(singleton2.get_value())    # Output: "New Value"

import hashlib
import time
import os
from functools import wraps

def cache_with_expiration(expiration_seconds=3600):
    """Decorator to cache function results with expiration and email anonymization."""
    _cache = {}

    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            cache_key = _generate_cache_key(func, args, kwargs)

            if cache_key in _cache:
                cached_result, timestamp = _cache[cache_key]
                if (time.time() - timestamp) < expiration_seconds:
                    return cached_result

            result = func(*args, **kwargs)
            anonymized_result = _anonymize_emails(result)
            _cache[cache_key] = (anonymized_result, time.time())

            return anonymized_result

        return wrapper

    return decorator

def _generate_cache_key(func, args, kwargs):
    """Generate a unique cache key."""
    return f"{func.__name__}-{str(args)}-{str(kwargs)}"

def _anonymize_emails(data):
    """Anonymize email addresses in the data."""
    if isinstance(data, str) and '@' in data:
        return _hash_email(data)
    elif isinstance(data, dict):
        return {k: _anonymize_emails(v) for k, v in data.items()}
    elif isinstance(data, (list, tuple, set)):
        return type(data)(_anonymize_emails(v) for v in data)
    return data

def _hash_email(email):
    """Hash the email address using SHA-256 and a salt."""
    salt = os.urandom(32)
    hashed = hashlib.sha256(salt + email.encode()).hexdigest()
    return f"anon-{hashed}"

import re
import argparse
from pathlib import Path
from abc import ABC, abstractmethod
from typing import List, Optional, Tuple

class FileProcessStrategy(ABC):
    """Abstract base class for file processing strategies."""

    @abstractmethod
    def process(self, file: Path, dry_run: bool = False) -> Tuple[Path, Path]:
        """Process a single file.

        Args:
            file: Path to the file to process
            dry_run: If True, only show what would be changed

        Returns:
            Tuple of (original_path, new_path)
        """
        pass

class RegexRenameStrategy(FileProcessStrategy):
    """Strategy for renaming files using regex patterns."""

    def __init__(self, pattern: str, replacement: str):
        """Initialize with regex pattern and replacement.

        Args:
            pattern: Regex pattern to match in filenames
            replacement: Replacement string (can use regex groups)
        """
        self.pattern = pattern
        self.replacement = replacement

    def process(self, file: Path, dry_run: bool = False) -> Tuple[Path, Path]:
        """Rename file using regex substitution."""
        new_name = re.sub(self.pattern, self.replacement, file.name)
        new_path = file.with_name(new_name)

        if not dry_run and new_path != file:
            file.rename(new_path)

        return (file, new_path)

class FileRenamer:
    """Main class for bulk file renaming."""

    def __init__(self, strategy: FileProcessStrategy):
        """Initialize with processing strategy."""
        self.strategy = strategy

    def process_files(self, files: List[Path], dry_run: bool = False) -> List[Tuple[Path, Path]]:
        """Process multiple files.

        Args:
            files: List of file paths to process
            dry_run: If True, only show what would be changed

        Returns:
            List of tuples (original_path, new_path)
        """
        results = []
        for file in files:
            if file.is_file():
                results.append(self.strategy.process(file, dry_run))
        return results

def get_files(directory: Path, recursive: bool = False) -> List[Path]:
    """Get files from directory, optionally recursively."""
    if recursive:
        return list(directory.rglob('*'))
    return list(directory.glob('*'))

def parse_args() -> argparse.Namespace:
    """Parse command line arguments."""
    parser = argparse.ArgumentParser(
        description="Bulk file renamer using regex patterns"
    )
    parser.add_argument(
        "pattern",
        help="Regex pattern to match in filenames"
    )
    parser.add_argument(
        "replacement",
        help="Replacement string (can use regex groups)"
    )
    parser.add_argument(
        "-d", "--directory",
        default=".",
        help="Directory containing files to rename (default: current directory)"
    )
    parser.add_argument(
        "-r", "--recursive",
        action="store_true",
        help="Process files recursively"
    )
    parser.add_argument(
        "-n", "--dry-run",
        action="store_true",
        help="Show what would be changed without actually renaming"
    )
    return parser.parse_args()

def main():
    args = parse_args()

    try:
        directory = Path(args.directory).resolve()
        if not directory.is_dir():
            raise ValueError(f"Directory not found: {directory}")

        files = get_files(directory, args.recursive)
        if not files:
            print("No files found to process")
            return

        strategy = RegexRenameStrategy(args.pattern, args.replacement)
        renamer = FileRenamer(strategy)

        results = renamer.process_files(files, args.dry_run)

        print(f"\n{'Dry run - ' if args.dry_run else ''}Processing results:")
        for original, new in results:
            if original != new:
                print(f"  {original.name} -> {new.name}")
            else:
                print(f"  {original.name} (no change)")

        changed = sum(1 for orig, new in results if orig != new)
        print(f"\nTotal files: {len(results)}, Changed: {changed}")

    except Exception as e:
        print(f"Error: {e}")

if __name__ == "__main__":
    main()

class FibonacciCacheStrategy:
    def __init__(self):
        self.cache = {}

    def get(self, n):
        return self.cache.get(n)

    def set(self, n, value):
        self.cache[n] = value

class FibonacciCalculator:
    def __init__(self, cache_strategy):
        self.cache_strategy = cache_strategy

    def fibonacci(self, n):
        if n <= 0:
            return 0
        elif n == 1:
            return 1
        cached_result = self.cache_strategy.get(n)
        if cached_result is not None:
            return cached_result
        result = self.fibonacci(n - 1) + self.fibonacci(n - 2)
        self.cache_strategy.set(n, result)
        return result

# Usage
cache_strategy = FibonacciCacheStrategy()
calculator = FibonacciCalculator(cache_strategy)
result = calculator.fibonacci(10)
print(result)

