def is_prime(n, k=5):
    """
    Miller-Rabin primality test.

    Parameters:
    n -- number to test
    k -- number of test rounds (higher means more accurate)

    Returns:
    True if n is probably prime, False if n is definitely composite
    """
    if n <= 1:
        return False
    elif n <= 3:
        return True
    elif n % 2 == 0:
        return False

    # Write n as d*2^s + 1
    d = n - 1
    s = 0
    while d % 2 == 0:
        d //= 2
        s += 1

    # Test k times
    for _ in range(k):
        a = random.randint(2, n - 2)
        x = pow(a, d, n)
        if x == 1 or x == n - 1:
            continue
        for __ in range(s - 1):
            x = pow(x, 2, n)
            if x == n - 1:
                break
        else:
            return False
    return True


