from abc import ABC, abstractmethod
from typing import Optional, Dict
import sqlite3

# Product model
class Product:
    def __init__(self, name: str, price: float, id: Optional[int] = None):
        self.id = id
        self.name = name
        self.price = price

# Order model
class Order:
    def __init__(self, product_id: int, quantity: int, id: Optional[int] = None):
        self.id = id
        self.product_id = product_id
        self.quantity = quantity

# Define repository interfaces
class ProductRepository(ABC):
    @abstractmethod
    def get_product_by_id(self, product_id: int) -> Optional[Product]:
        pass

    @abstractmethod
    def save_product(self, product: Product):
        pass

    @abstractmethod
    def update_product(self, product_id: int, product_details: Dict[str, str]):
        pass

    @abstractmethod
    def delete_product(self, product_id: int):
        pass

class OrderRepository(ABC):
    @abstractmethod
    def get_order_by_id(self, order_id: int) -> Optional[Order]:
        pass

    @abstractmethod
    def save_order(self, order: Order):
        pass

# Implement repository interfaces with SQL data access
class SQLProductRepository(ProductRepository):
    def __init__(self, db_connection):
        self.db_connection = db_connection

    def get_product_by_id(self, product_id: int) -> Optional[Product]:
        cursor = self.db_connection.cursor()
        cursor.execute('SELECT * FROM Products WHERE Id = ?', (product_id,))
        row = cursor.fetchone()
        return Product(id=row[0], name=row[1], price=row[2]) if row else None

    def save_product(self, product: Product):
        cursor = self.db_connection.cursor()
        if product.id:
            cursor.execute('INSERT OR REPLACE INTO Products (Id, Name, Price) VALUES (?, ?, ?)',
                           (product.id, product.name, product.price))
        else:
            cursor.execute('INSERT INTO Products (Name, Price) VALUES (?, ?)',
                           (product.name, product.price))
            product.id = cursor.lastrowid
        self.db_connection.commit()

    def update_product(self, product_id: int, product_details: Dict[str, str]):
        cursor = self.db_connection.cursor()
        cursor.execute('UPDATE Products SET Name = ?, Price = ? WHERE Id = ?',
                       (product_details['name'], product_details['price'], product_id))
        self.db_connection.commit()

    def delete_product(self, product_id: int):
        cursor = self.db_connection.cursor()
        cursor.execute('DELETE FROM Products WHERE Id = ?', (product_id,))
        self.db_connection.commit()

class SQLOrderRepository(OrderRepository):
    def __init__(self, db_connection):
        self.db_connection = db_connection

    def get_order_by_id(self, order_id: int) -> Optional[Order]:
        cursor = self.db_connection.cursor()
        cursor.execute('SELECT * FROM Orders WHERE Id = ?', (order_id,))
        row = cursor.fetchone()
        return Order(id=row[0], product_id=row[1], quantity=row[2]) if row else None

    def save_order(self, order: Order):
        cursor = self.db_connection.cursor()
        cursor.execute('INSERT INTO Orders (ProductId, Quantity) VALUES (?, ?)',
                       (order.product_id, order.quantity))
        self.db_connection.commit()
        order.id = cursor.lastrowid

# Define service layer
class ProductService:
    def __init__(self, product_repository: ProductRepository):
        self.product_repository = product_repository

    def get_product_details(self, product_id: int) -> Optional[Product]:
        return self.product_repository.get_product_by_id(product_id)

    def create_product(self, product_data: Dict[str, str]):
        product = Product(**product_data)
        self.product_repository.save_product(product)

    def update_product(self, product_id: int, product_data: Dict[str, str]):
        self.product_repository.update_product(product_id, product_data)

    def remove_product(self, product_id: int):
        self.product_repository.delete_product(product_id)

class OrderService:
    def __init__(self, order_repository: OrderRepository):
        self.order_repository = order_repository

    def get_order_details(self, order_id: int) -> Optional[Order]:
        return self.order_repository.get_order_by_id(order_id)

    def create_order(self, order_data: Dict[str, str]):
        order = Order(**order_data)
        self.order_repository.save_order(order)

# Using the services
def main():
    db_connection = sqlite3.connect('ecommerce.db')
    product_repository = SQLProductRepository(db_connection)
    order_repository = SQLOrderRepository(db_connection)

    product_service = ProductService(product_repository)
    order_service = OrderService(order_repository)

    # Example of creating a product
    product_details = {'name': 'New Product', 'price': 25.50}
    product_service.create_product(product_details)

    # Example of creating an order
    order_details = {'product_id': 1, 'quantity': 2}
    order_service.create_order(order_details)

if __name__ == '__main__':
    main()

