package main

import (
	"encoding/json"
	"net/http"
	"time"
	"github.com/sirupsen/logrus"
	"github.com/go-chi/chi/v5"
	"github.com/go-chi/chi/v5/middleware"
)

type ApiResponse struct {
	Status  string `json:"status"`
	Message string `json:"message"`
}

func main() {
	logger := logrus.New()
	logger.Formatter = &logrus.JSONFormatter{}
	logger.Level = logrus.InfoLevel

	r := chi.NewRouter()
	r.Use(middleware.RequestID)
	r.Use(middleware.Logger)
	r.Use(middleware.Recoverer)
	r.Use(middleware.Timeout(60 * time.Second))

	r.Get("/service", func(w http.ResponseWriter, r *http.Request) {
		response := ApiResponse{"ok", "Service is up and running"}
		respondWithJSON(w, http.StatusOK, response)
	})

	r.Post("/data", func(w http.ResponseWriter, r *http.Request) {
		var data map[string]interface{}
		err := json.NewDecoder(r.Body).Decode(&data)
		if err != nil {
			logger.WithFields(logrus.Fields{
				"error": err,
			}).Error("Failed to decode input data")
			respondWithError(w, http.StatusBadRequest, "Invalid request payload")
			return
		}

		if ok := externalAPIProcess(data); !ok {
			logger.Error("External API failure - Falling back to default response")
			response := ApiResponse{"fallback", "Processed with fallback data"}
			respondWithJSON(w, http.StatusOK, response)
			return
		}

		response := ApiResponse{"success", "Data processed successfully"}
		respondWithJSON(w, http.StatusOK, response)
	})

	http.ListenAndServe(":8080", r)
}

func externalAPIProcess(data map[string]interface{}) bool {
	// Simulating external API processing and their associated failures
	if _, ok := data["corrupt"]; ok {
		return false
	}
	return true
}

func respondWithJSON(w http.ResponseWriter, statusCode int, payload interface{}) {
	response, _ := json.Marshal(payload)
	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(statusCode)
	w.Write(response)
}

func respondWithError(w http.ResponseWriter, statusCode int, message string) {
	respondWithJSON(w, statusCode, ApiResponse{"error", message})
}

import React from 'react';
import PropTypes from 'prop-types';

const ThemeContext = React.createContext();

const withTheme = (Component) => (props) => (
  <ThemeContext.Consumer>
    {(theme) => <Component {...props} theme={theme} />}
  </ThemeContext.Consumer>
);

const Input = withTheme(({ theme, type, value, onChange, placeholder }) => (
  <input
    type={type}
    value={value}
    onChange={onChange}
    placeholder={placeholder}
    style={{ ...theme.input }}
  />
));

Input.propTypes = {
  theme: PropTypes.object.isRequired,
  type: PropTypes.string,
  value: PropTypes.string,
  onChange: PropTypes.func,
  placeholder: PropTypes.string
};

Input.defaultProps = {
  type: 'text',
  value: '',
  onChange: () => {},
  placeholder: ''
};

const Select = withTheme(({ theme, options, value, onChange }) => (
  <select
    value={value}
    onChange={onChange}
    style={{ ...theme.select }}
  >
    {options.map((option, index) => (
      <option key={index} value={option.value}>
        {option.label}
      </option>
    ))}
  </select>
));

Select.propTypes = {
  theme: PropTypes.object.isRequired,
  options: PropTypes.arrayOf(PropTypes.shape({
    value: PropTypes.string.isRequired,
    label: PropTypes.string.isRequired
  })),
  value: PropTypes.string,
  onChange: PropTypes.func
};

Select.defaultProps = {
  options: [],
  value: '',
  onChange: () => {}
};

const Checkbox = withTheme(({ theme, label, isChecked, onChange }) => (
  <label style={{ ...theme.checkboxLabel }}>
    <input
      type="checkbox"
      checked={isChecked}
      onChange={onChange}
      style={{ ...theme.checkbox }}
    />
    {label}
  </label>
));

Checkbox.propTypes = {
  theme: PropTypes.object.isRequired,
  label: PropTypes.string,
  isChecked: PropTypes.bool,
  onChange: PropTypes.func
};

Checkbox.defaultProps = {
  label: '',
  isChecked: false,
  onChange: () => {}
};

const Radio = withTheme(({ theme, name, options, selectedValue, onChange }) => (
  <div>
    {options.map((option, index) => (
      <label key={index} style={{ ...theme.radioLabel }}>
        <input
          type="radio"
          name={name}
          value={option.value}
          checked={selectedValue === option.value}
          onChange={onChange}
          style={{ ...theme.radio }}
        />
        {option.label}
      </label>
    ))}
  </div>
));

Radio.propTypes = {
  theme: PropTypes.object.isRequired,
  name: PropTypes.string.isRequired,
  options: PropTypes.arrayOf(PropTypes.shape({
    value: PropTypes.string.isRequired,
    label: PropTypes.string.isRequired
  })),
  selectedValue: PropTypes.string,
  onChange: PropTypes.func
};

Radio.defaultProps = {
  options: [],
  selectedValue: '',
  onChange: () => {}
};

export const FormControlsProvider = ({ theme, children }) => (
  <ThemeContext.Provider value={theme}>
    {children}
  </ThemeContext.Provider>
);

export { Input, Select, Checkbox, Radio };

import datetime
from typing import List, Optional
from dataclasses import dataclass, field
import uuid

@dataclass(frozen=True)
class TransactionRecord:
    user_id: str
    timestamp: datetime.datetime
    action: str
    details: str
    transaction_id: str = field(default_factory=lambda: str(uuid.uuid4()))

    def __repr__(self):
        return f"{self.timestamp} - {self.user_id} - {self.action}: {self.details} (ID: {self.transaction_id})"

class ImmutableLedger:
    def __init__(self):
        self._records: List[TransactionRecord] = []

    def add_record(self, user_id: str, action: str, details: str):
        timestamp = datetime.datetime.now()
        record = TransactionRecord(user_id=user_id, timestamp=timestamp, action=action, details=details)
        self._records.append(record)

    def get_records(self, user_id: Optional[str] = None) -> List[TransactionRecord]:
        if user_id:
            return [record for record in self._records if record.user_id == user_id]
        return self._records.copy()

    def __repr__(self):
        return "\n".join(repr(record) for record in self._records)

if __name__ == "__main__":
    ledger = ImmutableLedger()
    ledger.add_record(user_id="User123", action="Deposit", details="Deposited $500")
    ledger.add_record(user_id="User456", action="Withdrawal", details="Withdrew $100")
    ledger.add_record(user_id="User123", action="Transfer", details="Transferred $300 to User456")

    print(ledger)
    print("\nFiltered by User123:")
    print(ledger.get_records("User123"))

