from flask import Flask, request, jsonify, redirect
import psycopg2
from psycopg2.pool import ThreadedConnectionPool
import hashlib
import os

app = Flask(__name__)

# Connection pool settings
min_conn = 1
max_conn = 20
db_configs = {
    "user": "username",
    "password": "password",
    "host": "replicated_db_primary_dns",
    "port": "5432",
    "database": "urls_db"
}

# Setup connection pool
connection_pool = ThreadedConnectionPool(min_conn, max_conn, **db_configs)

def get_db_connection():
    def test_conn(conn):
        try:
            with conn.cursor() as cursor:
                cursor.execute("SELECT 1")
                if cursor.fetchone():
                    return True
                else:
                    return False
        except Exception:
            return False

    conn = connection_pool.getconn()
    if not test_conn(conn):
        conn.reset()
        if not test_conn(conn):
            # Attempt to connect to secondary replica
            db_configs_secondary = db_configs.copy()
            db_configs_secondary["host"] = "replicated_db_secondary_dns"
            secondary_pool = ThreadedConnectionPool(min_conn, max_conn, **db_configs_secondary)
            conn = secondary_pool.getconn()
            if not test_conn(conn):
                raise ValueError("All connections failed")
    return conn

def insert_url_mapping(short_url, long_url):
    conn = get_db_connection()
    try:
        with conn.cursor() as cursor:
            cursor.execute("INSERT INTO url_mappings (short_url, long_url) VALUES (%s, %s)", (short_url, long_url))
        conn.commit()
    finally:
        connection_pool.putconn(conn)

def get_long_url(short_url):
    conn = get_db_connection()
    try:
        with conn.cursor() as cursor:
            cursor.execute("SELECT long_url FROM url_mappings WHERE short_url = %s", (short_url,))
            result = cursor.fetchone()
            return result[0] if result else None
    finally:
        connection_pool.putconn(conn)

def generate_short_url(long_url):
    # Use MD5 hash of the long URL for demo purposes
    short_hash = hashlib.md5(long_url.encode()).hexdigest()[:6]
    # Ensure uniqueness
    while get_long_url(short_hash):
        short_hash = hashlib.md5((long_url + os.urandom(1).hex()).encode()).hexdigest()[:6]
    return short_hash

@app.route('/shorten', methods=['POST'])
def shorten_url():
    long_url = request.get_json().get('long_url')
    if not long_url:
        return jsonify({"error": "No URL provided"}), 400
    short_url = generate_short_url(long_url)
    insert_url_mapping(short_url, long_url)
    return jsonify({"short_url": short_url}), 201

@app.route('/<short_url>', methods=['GET'])
def redirect_url(short_url):
    long_url = get_long_url(short_url)
    if long_url:
        return redirect(long_url)
    return jsonify({"error": "URL not found"}), 404

if __name__ == "__main__":
    app.run(port=5000)

