import time
import random
from requests import get
from requests.exceptions import RequestException

class CircuitBreaker:
    def __init__(self, failure_threshold=3, recovery_threshold=5, base_backoff=1, max_backoff=60):
        self.failure_threshold = failure_threshold
        self.recovery_threshold = recovery_threshold
        self.failures = 0
        self.successes = 0
        self.state = 'CLOSED'
        self.base_backoff = base_backoff
        self.max_backoff = max_backoff
        self.next_allowed_time = 0

    def call(self, url):
        if self.state == 'OPEN':
            if time.time() < self.next_allowed_time:
                print("Circuit is OPEN. Request not allowed.")
                return
            else:
                self.state = 'HALF_OPEN'
                print(f"Transitioned to HALF_OPEN state. Testing with request to {url}")

        try:
            response = get(url)
            self.record_success()
            return response
        except RequestException:
            self.record_failure()
            raise

    def record_success(self):
        self.failures = 0
        if self.state == 'HALF_OPEN':
            self.successes += 1
            if self.successes >= self.recovery_threshold:
                self.reset()
                print("Transitioned to CLOSED state")
        else:
            self.successes = 0

    def record_failure(self):
        self.failures += 1
        self.successes = 0
        if self.state != 'HALF_OPEN' and self.failures >= self.failure_threshold:
            self.enter_open_state()

    def enter_open_state(self):
        self.state = 'OPEN'
        self.next_allowed_time = time.time() + self.calculate_backoff()
        print(f"Transitioned to OPEN state. Next allowed time: {self.next_allowed_time}")

    def calculate_backoff(self):
        return min(self.base_backoff * (2 ** (self.failures - self.failure_threshold)), self.max_backoff)

    def reset(self):
        self.state = 'CLOSED'
        self.failures = 0
        self.successes = 0

# Example usage:

circuit_breaker = CircuitBreaker()

for _ in range(20):
    try:
        print(circuit_breaker.call('https://api.example.com'))
    except Exception as e:
        print(e)
    time.sleep(1)

import hashlib
import random
import threading
from collections import defaultdict
import time
import json
import socket

class Node:
    def __init__(self, node_id):
        self.node_id = node_id
        self.data = {}

    def __repr__(self):
        return f"Node({self.node_id})"

class ConsistentHashing:
    def __init__(self, num_vnodes=100):
        self.num_vnodes = num_vnodes
        self.ring = []
        self.vnode_to_node = {}
        self.nodes = []

    def _hash(self, key):
        return int(hashlib.md5(key.encode('utf-8')).hexdigest(), 16)

    def add_node(self, node):
        self.nodes.append(node)
        for i in range(self.num_vnodes):
            hsh = self._hash(f"{node.node_id}_vnode_{i}")
            self.ring.append(hsh)
            self.vnode_to_node[hsh] = node
        self.ring.sort()
        self.redistribute_data()

    def remove_node(self, node):
        self.nodes.remove(node)
        to_remove = [self._hash(f"{node.node_id}_vnode_{i}") for i in range(self.num_vnodes)]
        self.ring = [h for h in self.ring if h not in to_remove]
        for hsh in to_remove:
            del self.vnode_to_node[hsh]
        self.redistribute_data()

    def get_node(self, key):
        hsh = self._hash(key)
        pos = next((i for i, h in enumerate(self.ring) if h >= hsh), 0)
        return self.vnode_to_node[self.ring[pos]]

    def redistribute_data(self):
        all_data = defaultdict(dict)
        for node in self.nodes:
            for k, v in node.data.items():
                responsible_node = self.get_node(k)
                all_data[responsible_node.node_id][k] = v
            node.data.clear()
        for node_id, data in all_data.items():
            for node in self.nodes:
                if node.node_id == node_id:
                    node.data.update(data)

class GossipProtocol:
    def __init__(self, nodes, local_node_id):
        self.nodes = nodes
        self.local_node_id = local_node_id
        self.membership_list = {node.node_id: {'last_seen': time.time()} for node in nodes}
        self.lock = threading.Lock()

    def gossip(self):
        while True:
            with self.lock:
                other_node = random.choice([node for node in self.nodes if node.node_id != self.local_node_id])
            self.send_membership_table(other_node.node_id)
            time.sleep(1)

    def send_membership_table(self, node_id):
        data = json.dumps(self.membership_list).encode('utf-8')
        sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        sock.sendto(data, (node_id, 50000))

    def receive_membership_table(self):
        sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        sock.bind((self.local_node_id, 50000))
        while True:
            data, _ = sock.recvfrom(4096)
