// Import dependencies
const express = require('express');
const axios = require('axios');
const cookieParser = require('cookie-parser');
const csrf = require('csurf');
const helmet = require('helmet');

// OAuth 2.1 settings
const oauth2Config = {
  clientId: 'YOUR_CLIENT_ID',
  clientSecret: 'YOUR_CLIENT_SECRET',
  redirectUri: 'https://your-spa.com/callback',
  authorizationEndpoint: 'https://authorization-server.com/oauth2/authorize',
  tokenEndpoint: 'https://authorization-server.com/oauth2/token',
  scopes: ['openid', 'profile', 'email'],
};

// Create Express app
const app = express();

// Helmet for setting Content-Security-Policy
app.use(helmet({
  contentSecurityPolicy: {
    directives: {
      defaultSrc: ["'self'"],
      scriptSrc: ["'self'"],
      objectSrc: ["'none'"],
      upgradeInsecureRequests: [],
    },
  }
}));

// Parse cookies
app.use(cookieParser('your-cookie-secret'));

// CSRF protection
const csrfProtection = csrf({ cookie: true });
app.use(csrfProtection);

// Generate a secure random string for PKCE
const generateRandomString = (length) => {
  return require('crypto').randomBytes(length).toString('hex');
};

// Generate code challenge for PKCE
const generateCodeChallenge = (codeVerifier) => {
  return require('crypto')
    .createHash('sha256')
    .update(codeVerifier)
    .digest()
    .toString('base64')
    .replace(/\+/g, '-')
    .replace(/\//g, '_')
    .replace(/=/g, '');
};

// Store generated state and code_verifier in memory
let states = {};
let codeVerifiers = {};

// Login route
app.get('/login', (req, res) => {
  const state = generateRandomString(32);
  const codeVerifier = generateRandomString(32);
  const codeChallenge = generateCodeChallenge(codeVerifier);

  states[state] = true;
  codeVerifiers[state] = codeVerifier;

  const queryParams = new URLSearchParams({
    client_id: oauth2Config.clientId,
    redirect_uri: oauth2Config.redirectUri,
    response_type: 'code',
    code_challenge_method: 'S256',
    code_challenge: codeChallenge,
    state: state,
    scope: oauth2Config.scopes.join(' '),
  });

  res.redirect(`${oauth2Config.authorizationEndpoint}?${queryParams}`);
});

// OAuth callback route
app.get('/callback', async (req, res) => {
  const { code, state } = req.query;

  if (!states[state]) {
    return res.status(403).send('State mismatch or expired');
  }

  const codeVerifier = codeVerifiers[state];
  delete states[state];
  delete codeVerifiers[state];

  try {
    const response = await axios.post(oauth2Config.tokenEndpoint, new URLSearchParams({
      client_id: oauth2Config.clientId,
      client_secret: oauth2Config.clientSecret,
      code,
      code_verifier: codeVerifier,
      grant_type: 'authorization_code',
      redirect_uri: oauth2Config.redirectUri,
    }), {
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
      },
    });

    if (response.data.access_token) {
      res.cookie('access_token', response.data.access_token, {
        httpOnly: true, 
        secure: true, 
        sameSite: 'Strict',
        maxAge: 3600000, // Token expiry time
        signed: true
      });

      res.cookie('refresh_token', response.data.refresh_token, {
        httpOnly: true, 
        secure: true, 
        sameSite: 'Strict',
        maxAge: 86400000, // Refresh token expiry time
        signed: true
      });

      res.send('Login Successful');
    } else {
      res.status(500).send('Error acquiring tokens');
    }
  } catch (error) {
    res.status(500).send('Authentication failed');
  }
});

// Token rotation
app.get('/refresh', async (req, res) => {
  const refreshToken = req.signedCookies.refresh_token;

  if (!refreshToken) {
    return res.status(401).send('Refresh token missing');
  }

  try {
    const response = await axios.post(oauth2Config.tokenEndpoint, new URLSearchParams({
      client_id: oauth2Config.clientId,
      client_secret: oauth2Config.clientSecret,
      grant_type: 'refresh_token',
      refresh_token: refreshToken,
    }), {
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
      },
    });

    if (response.data.access_token) {
      res.cookie('access_token', response.data.access_token, {
        httpOnly: true, 
        secure: true, 
        sameSite: 'Strict',
        maxAge: 3600000, 
        signed: true
      });

      res.send('Token refreshed');
    } else {
      res.status(500).send('Error refreshing token');
    }
  } catch (error) {
    res.status(500).send('Token refresh failed');
  }
});

// Example of a protected route
app.get('/protected', csrfProtection, (req, res) => {
  const token = req.signedCookies.access_token;

  if (!token) {
    return res.status(401).send('Unauthorized access');
  }

  res.send('Protected content');
});

// Set port and start server
const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Listening on port ${PORT}`);
});

