package main

import (
	"bufio"
	"compress/gzip"
	"fmt"
	"io"
	"log"
	"os"
	"runtime"
	"strings"
	"sync"
	"testing"
)

const (
	bufferSize = 32 * 1024
	lineSize   = 256
)

var linePool = sync.Pool{
	New: func() interface{} {
		return make([]byte, 0, lineSize)
	},
}

func parseLogLine(line []byte) {
	// Example parsing, modify to match log format
	if len(line) > 0 {
		_ = strings.Split(string(line), " ")
	}
}

func processLogs(r io.Reader, numWorkers int) {
	gzipReader, err := gzip.NewReader(r)
	if err != nil {
		log.Fatalf("Failed to create Gzip reader: %v", err)
	}
	defer gzipReader.Close()

	scanner := bufio.NewScanner(gzipReader)
	scanner.Buffer(make([]byte, bufferSize), lineSize)

	lines := make(chan []byte, numWorkers*4)

	var wg sync.WaitGroup
	wg.Add(numWorkers)
	for i := 0; i < numWorkers; i++ {
		go func() {
			defer wg.Done()
			for line := range lines {
				parseLogLine(line)
				linePool.Put(line[:0])
			}
		}()
	}

	go func() {
		for scanner.Scan() {
			line := linePool.Get().([]byte)
			line = append(line[:0], scanner.Bytes()...)
			lines <- line
		}
		close(lines)
	}()

	wg.Wait()

	if err := scanner.Err(); err != nil {
		log.Printf("Scanner error: %v", err)
	}
}

func benchmarkProcessLogs(b *testing.B, file string) {
	b.SetBytes(1e6)
	b.ReportAllocs()

	for n := 0; n < b.N; n++ {
		f, err := os.Open(file)
		if err != nil {
			b.Fatalf("Failed to open file: %v", err)
		}

		_, err = f.Seek(0, io.SeekStart)
		if err != nil {
			b.Fatalf("Failed to seek file: %v", err)
		}
		processLogs(f, runtime.NumCPU())
		f.Close()
	}
}

func BenchmarkLogParsing(b *testing.B) {
	files := []string{"logfile1.gz", "logfile2.gz"} // Example files
	for _, file := range files {
		b.Run(file, func(b *testing.B) {
			benchmarkProcessLogs(b, file)
		})
	}
}

func main() {
	const numWorkers = 8
	file, err := os.Open("your_log_file.gz")
	if err != nil {
		log.Fatalf("Error opening gzip file: %v", err)
	}
	defer file.Close()
	processLogs(file, numWorkers)

	fmt.Println("Log processing completed.")
}

const express = require('express');
const jwt = require('jsonwebtoken');
const bodyParser = require('body-parser');
const cookieParser = require('cookie-parser');
const crypto = require('crypto');
const csrf = require('csurf');

const app = express();
app.use(bodyParser.json());
app.use(cookieParser());

const ACCESS_TOKEN_SECRET = 'your_access_token_secret';
const REFRESH_TOKEN_SECRET = 'your_refresh_token_secret';
let refreshTokens = new Map(); // { userId: {refreshToken, timestamp}}
let revokedTokens = new Set();

const csrfProtection = csrf({ cookie: true });
app.use(csrfProtection);

const generateAccessToken = (user) => {
  return jwt.sign(user, ACCESS_TOKEN_SECRET, { expiresIn: '15m' });
};

const generateRefreshToken = (user) => {
  const refreshToken = jwt.sign(user, REFRESH_TOKEN_SECRET);
  refreshTokens.set(user.userId, { token: refreshToken, timestamp: Date.now() });
  return refreshToken;
};

const verifyToken = (req, res, next) => {
  const token = req.headers['authorization']?.split(' ')[1];

  if (!token) return res.sendStatus(401);
  if (revokedTokens.has(token)) return res.sendStatus(403);

  jwt.verify(token, ACCESS_TOKEN_SECRET, (err, user) => {
    if (err) return res.sendStatus(403);
    req.user = user;
    next();
  });
};

const preventReplayAttacks = (req, res, next) => {
  const nonce = req.headers['replay-nonce'];
  if (!nonce) return res.status(403).json({ message: "Replay nonce required" });

  const hash = crypto.createHmac('sha256', ACCESS_TOKEN_SECRET).update(nonce).digest('hex');
  if (revokedTokens.has(hash)) {
    return res.status(403).json({ message: "Replay attack detected" });
  }

  revokedTokens.add(hash);
  next();
};

app.post('/login', (req, res) => {
  const user = { userId: req.body.userId };
  const accessToken = generateAccessToken(user);
  const refreshToken = generateRefreshToken(user);
  res.json({ accessToken, refreshToken });
});

app.post('/token', (req, res) => {
  const { refreshToken } = req.body;
  if (!refreshToken) return res.sendStatus(401);

  for (let [userId, value] of refreshTokens.entries()) {
    if (value.token === refreshToken) {
      jwt.verify(refreshToken, REFRESH_TOKEN_SECRET, (err, user) => {
        if (err) return res.sendStatus(403);

        const accessToken = generateAccessToken({ userId: user.userId });
        res.json({ accessToken });
      });
      return;
    }
  }
  res.sendStatus(403);
});

app.post('/logout', verifyToken, (req, res) => {
  const token = req.headers['authorization'].split(' ')[1];
  revokedTokens.add(token);
  res.status(200).json({ message: "Logged out successfully" });
});

app.get('/protected', verifyToken, csrfProtection, preventReplayAttacks, (req, res) => {
  res.json({ message: `Welcome user ${req.user.userId}` });
});

app.listen(3000, () => {
  console.log('Server running on port 3000');
});

