use actix_web::{web, App, Error, HttpResponse, HttpServer};
use actix_multipart::Multipart;
use futures::{StreamExt, TryStreamExt};
use serde::{Deserialize, Serialize};
use std::fs::{self, File};
use std::io::{self, Write};
use uuid::Uuid;
use std::sync::{Arc, Mutex};
use rusqlite::{params, Connection};
use log::{error, info};

#[derive(Serialize, Deserialize)]
struct FileUpload {
    id: String,
    file_name: String,
    total_chunks: u64,
    chunks_received: u64,
}

#[derive(Clone)]
struct AppState {
    db_conn: Arc<Mutex<Connection>>,
    max_retries: u8,
}

async fn handle_upload(mut payload: Multipart, data: web::Data<AppState>) -> Result<HttpResponse, Error> {
    while let Ok(Some(mut field)) = payload.try_next().await {
        let content_disposition = field.content_disposition().unwrap();
        let file_name = content_disposition.get_filename().unwrap().to_string();
        let file_id = Uuid::new_v4().to_string();

        let file_path = format!("./uploads/{}", file_id);
        fs::create_dir_all("./uploads")?;
        let mut f = File::create(file_path.clone()).map_err(|e| {
            error!("Failed to create file: {}. Error: {:?}", file_path, e);
            e
        })?;

        let mut chunks = 0;
        while let Some(chunk) = field.next().await {
            let data = chunk.unwrap();
            let mut retries = 0;
            loop {
                match f.write_all(&data) {
                    Ok(_) => {
                        info!("Successfully wrote chunk {}/{} for file {}", chunks + 1, chunks_received, file_name);
                        break;
                    },
                    Err(e) => {
                        if retries < data.max_retries {
                            retries += 1;
                            error!("Error writing chunk: {}. Retrying {}/{}. Error: {:?}", chunks + 1, retries, data.max_retries, e);
                        } else {
                            error!("Failed to write chunk after {} retries: {}. Error: {:?}", retries, chunks + 1, e);
                            return Ok(HttpResponse::InternalServerError().finish());
                        }
                    }
                }
            }
            chunks += 1;
        }

        let mut db = data.db_conn.lock().unwrap();
        db.execute(
            "INSERT INTO uploads (id, file_name, total_chunks, chunks_received) VALUES (?1, ?2, ?3, ?4)",
            params![file_id, file_name, chunks, chunks],
        ).map_err(|e| {
            error!("Failed to insert into database: {:?}", e);
            e
        })?;
    }

    Ok(HttpResponse::Ok().finish())
}

async fn setup_db() -> Result<Connection, rusqlite::Error> {
    let conn = Connection::open("uploads.db")?;
    conn.execute(
        "CREATE TABLE IF NOT EXISTS uploads (
            id TEXT PRIMARY KEY,
            file_name TEXT NOT NULL,
            total_chunks INTEGER NOT NULL,
            chunks_received INTEGER NOT NULL
            )",
        [],
    )?;
    Ok(conn)
}

#[actix_web::main]
async fn main() -> io::Result<()> {
    env_logger::init();

    let db_conn = Arc::new(Mutex::new(setup_db().await.expect("Failed to setup database")));

    HttpServer::new(move || {
        App::new()
            .app_data(web::Data::new(AppState {
                db_conn: db_conn.clone(),
                max_retries: 3,
            }))
            .route("/upload", web::post().to(handle_upload))
    })
    .bind("0.0.0.0:8080")?
    .run()
    .await
}

import React, { useState, useCallback } from 'react';
import { JSONSchema7 } from 'json-schema';
import Ajv from 'ajv';
import 'react-select/dist/react-select.css';
import Select from 'react-select';

const ajv = new Ajv();

interface Props {
  initialSchema: JSONSchema7;
}

const defaultSchema: JSONSchema7 = {
  type: 'object',
  properties: {},
};

const typeOptions = [
  { value: 'string', label: 'String' },
  { value: 'number', label: 'Number' },
  { value: 'object', label: 'Object' },
  { value: 'array', label: 'Array' },
  { value: 'boolean', label: 'Boolean' },
  { value: 'null', label: 'Null' },
];

const JsonSchemaEditor: React.FC<Props> = ({ initialSchema }) => {
  const [schema, setSchema] = useState<JSONSchema7>(initialSchema || defaultSchema);
  const [data, setData] = useState({});
  const [errors, setErrors] = useState<Ajv.ErrorObject[] | null>(null);
  const [history, setHistory] = useState<JSONSchema7[]>([]);
  const [future, setFuture] = useState<JSONSchema7[]>([]);

  const validate = () => {
    const validate = ajv.compile(schema);
    const valid = validate(data);
    setErrors(valid ? null : validate.errors);
  };

  const undo = useCallback(() => {
    if (history.length > 0) {
      setFuture([schema, ...future]);
      const previous = history[history.length - 1];
      setHistory(history.slice(0, -1));
      setSchema(previous);
    }
  }, [schema, history, future]);

  const redo = useCallback(() => {
    if (future.length > 0) {
      setHistory([...history, schema]);
      const next = future[0];
      setFuture(future.slice(1));
      setSchema(next);
    }
  }, [schema, history, future]);

  const updateSchema = useCallback((updatedSchema: JSONSchema7) => {
    setHistory([...history, schema]);
    setSchema(updatedSchema);
    setFuture([]);
  }, [schema, history]);

  const handleChange = (path: string, value: any) => {
    const newData = { ...data };
    const pathArray = path.split('.');
    pathArray.reduce((acc, key, idx) => {
      if (idx === pathArray.length - 1) {
        acc[key] = value;
        return value;
      }
      return acc[key] = acc[key] || {};
    }, newData);
    setData(newData);
    validate();
  };

  const handleTypeChange = (path: string, type: string) => {
    const schemaPath = path.split('.');
    let currentSchema = { ...schema };
    schemaPath.reduce((acc, key, idx) => {
      if (idx === schemaPath.length - 1) {
        if (acc.properties) {
          acc.properties[key] = { type };
        }
      }
      return acc.properties ? acc.properties[key] : {};
    }, currentSchema);
    updateSchema(currentSchema);
  };

  const handleAddField = (path: string) => {
    const newField: JSONSchema7 = { type: 'string' };
    const schemaPath = path.split('.');
    let currentSchema = { ...schema };
    schemaPath.reduce((acc, key, idx) => {
      if (idx === schemaPath.length - 1) {
        if (!acc.properties) {
          acc.properties = {};
        }
        acc.properties[`newField${Object.keys(acc.properties).length}`] = newField;
      }
      return acc.properties ? acc.properties[key] : {};
    }, currentSchema);
    updateSchema(currentSchema);
  };

  const renderField = (schema: JSONSchema7, path: string) => {
    if (schema.type === 'object' && schema.properties) {
      return (
        <div style={{ marginLeft: 20 }}>
          {Object.entries(schema.properties).map(([key, subSchema]) => (
            <div key={key}>
              <div>
                <span>{key}: {subSchema.type}</span>
                <Select
                  options={typeOptions}
                  onChange={(option) => handleTypeChange(`${path}.${key}`, option!.value)}
                  defaultValue={typeOptions.find(opt => opt.value === subSchema.type)}
                />
                <button onClick={() => handleAddField(`${path}.${key}`)}>Add Field</button>
              </div>
              {subSchema.description && <div><span title={subSchema.description}>ℹ️</span></div>}
              {renderField(subSchema as JSONSchema7, `${path}.${key}`)}
            </div>
          ))}
        </div>
      );
    }
    return null;
  };

  return (
    <div>
      <h1>JSON Schema Editor</h1>
      <button onClick={undo} disabled={history.length === 0}>Undo</button>
      <button onClick={redo} disabled={future.length === 0}>Redo</button>
      <form>
        {renderField(schema, '')}
      </form>
      {errors && (
        <div>
          <h2>Validation Errors:</h2>
          <ul>
            {errors.map(error => (
              <li key={error.message}>{error.message}</li>
            ))}
          </ul>
        </div>
      )}
    </div>
  );
};

export default JsonSchemaEditor;

package main

import (
	"crypto/rand"
	"crypto/sha256"
	"encoding/base64"
	"log"
	"net/http"
	"time"

	"github.com/golang-jwt/jwt"
	"github.com/gorilla/mux"
	"github.com/gorilla/sessions"
	"github.com/throttled/throttled/v2"
	"github.com/throttled/throttled/v2/store/memstore"
	"golang.org/x/oauth2"
)

const (
	clientID     = "your-client-id"
	clientSecret = "your-client-secret"
	redirectURL  = "https://your-redirect-url.com/callback"
	sessionKey   = "yoursecretsessionkey"
)

// Session store
var store = sessions.NewCookieStore([]byte(sessionKey))

// OAuth2 Configuration
var oauthConf = &oauth2.Config{
	ClientID:     clientID,
	ClientSecret: clientSecret,
	RedirectURL:  redirectURL,
	Endpoint: oauth2.Endpoint{
		AuthURL:  "https://provider.com/oauth2/auth",
		TokenURL: "https://provider.com/oauth2/token",
	},
}

func main() {
	router := mux.NewRouter()
	store.Options = &sessions.Options{
		Path:     "/",
		MaxAge:   86400 * 7, // 7 days
		HttpOnly: true,
		Secure:   true,
	}

	// Rate Limiter setup
	rateLimiter, err := throttled.NewGCRARateLimiter(memstore.New(65536), throttled.RateQuota{
		MaxRate:  throttled.PerMinute(20),
		MaxBurst: 10,
	})
	if err != nil {
		log.Fatalf("Failed to create rate limiter: %v", err)
	}
	httpRateLimiter := &throttled.HTTPRateLimiter{
		RateLimiter: rateLimiter,
		VaryBy:      &throttled.VaryBy{Path: true},
	}

	// Route handlers
	router.HandleFunc("/auth", authHandler)
	router.HandleFunc("/callback", callbackHandler)
	router.HandleFunc("/token/revoke", revokeTokenHandler)
	router.HandleFunc("/logs", logHandler)

	// Middleware for TLS and rate limiting
	router.Use(forceTLS)
	router.Use(httpRateLimiter.RateLimit)

	// Start server with TLS enforcement
	log.Fatal(http.ListenAndServeTLS(":443", "server.crt", "server.key", router))
}

func authHandler(w http.ResponseWriter, r *http.Request) {
	logAction("Auth handler started")

	state := generateRandomString(32)
	setSessionValue(r, "state", state)

	codeVerifier := generateRandomString(64)
	codeChallenge := generateCodeChallenge(codeVerifier)
	setSessionValue(r, "code_verifier", codeVerifier)

	url := oauthConf.AuthCodeURL(state, oauth2.AccessTypeOffline, oauth2.SetAuthURLParam("code_challenge", codeChallenge), oauth2.SetAuthURLParam("code_challenge_method", "S256"))
	http.Redirect(w, r, url, http.StatusTemporaryRedirect)
	logAction("Auth handler completed")
}

func callbackHandler(w http.ResponseWriter, r *http.Request) {
	logAction("Callback handler started")

	savedState := getSessionValue(r, "state")
	if r.URL.Query().Get("state") != savedState {
		http.Error(w, "Invalid state parameter", http.StatusBadRequest)
		return
	}

	code := r.URL.Query().Get("code")
	if code == "" {
		http.Error(w, "Missing code", http.StatusBadRequest)
		return
	}

	codeVerifier := getSessionValue(r, "code_verifier")
	token, err := oauthConf.Exchange(r.Context(), code, oauth2.SetAuthURLParam("code_verifier", codeVerifier))
	if err != nil {
		http.Error(w, "Failed to exchange token", http.StatusInternalServerError)
		return
	}

	log.Printf("Token acquired: %s", token.AccessToken)
	http.Redirect(w, r, "/", http.StatusSeeOther)
	logAction("Callback handler completed")
}

func revokeTokenHandler(w http.ResponseWriter, r *http.Request) {
	logAction("Revoke token handler started")

	token := r.URL.Query().Get("token")
	if token == "" {
		http.Error(w, "Token required", http.StatusBadRequest)
		return
	}

	log.Printf("Token revoked: %s", token)
	w.WriteHeader(http.StatusOK)
	logAction("Revoke token handler completed")
}

func logHandler(w http.ResponseWriter, r *http.Request) {
	logAction("Log handler accessed")
	http.Error(w, "Logs not implemented", http.StatusNotImplemented)
}

func generateRandomString(length int) string {
	b := make([]byte, length)
	_, err := rand.Read(b)
	if err != nil {
		log.Fatalf("Failed to generate random string: %v", err)
	}
	return base64.URLEncoding.EncodeToString(b)
}

func generateCodeChallenge(verifier string) string {
	h := sha256.New()
	h.Write([]byte(verifier))
	return base64.URLEncoding.EncodeToString(h.Sum(nil))
}

func setSessionValue(r *http.Request, key string, value string) {
	session, _ := store.Get(r, "session-name")
	session.Values[key] = value
	session.Save(r, nil)
}

func getSessionValue(r *http.Request, key string) string {
	session, _ := store.Get(r, "session-name")
	if val, ok := session.Values[key].(string); ok {
		return val
	}
	return ""
}

func forceTLS(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		if r.URL.Scheme != "https" && r.Header.Get("X-Forwarded-Proto") != "https" {
			http.Error(w, "TLS required", http.StatusUpgradeRequired)
			return
		}
		next.ServeHTTP(w, r)
	})
}

func logAction(description string) {
	log.Println(description)
}

