const std::size_t CHUNK_SIZE = 512 * 1024 * 1024; // 512 MB
const std::size_t MAX_MEMORY = 8 * 1024 * 1024 * 1024; // 8 GB
const std::size_t BUFFER_SIZE = 4 * 1024; // 4 KB for buffered I/O

std::mutex mtx;
std::condition_variable cond_var;

void sortChunk(std::string inputFilePath, int chunkIndex) {
    std::ifstream in(inputFilePath, std::ios::binary);
    std::vector<int> buffer;
    std::string chunkFileName = "chunk" + std::to_string(chunkIndex) + ".bin";

    in.seekg(chunkIndex * CHUNK_SIZE * sizeof(int), std::ios::beg);
    buffer.resize(CHUNK_SIZE / sizeof(int));
    in.read(reinterpret_cast<char*>(buffer.data()), CHUNK_SIZE);

    std::size_t numRead = in.gcount() / sizeof(int);
    buffer.resize(numRead);

    std::sort(buffer.begin(), buffer.end());

    std::ofstream out(chunkFileName, std::ios::binary);
    out.rdbuf()->pubsetbuf(new char[BUFFER_SIZE], BUFFER_SIZE);
    out.write(reinterpret_cast<const char*>(buffer.data()), numRead * sizeof(int));
}

void mergeChunks(std::string outputFilePath, int numChunks) {
    auto comparator = [](const std::pair<int, int>& left, const std::pair<int, int>& right) {
        return left.first > right.first;
    };

    std::priority_queue<std::pair<int, int>, std::vector<std::pair<int, int>>, decltype(comparator)> minHeap(comparator);
    std::vector<std::ifstream> chunkFiles(numChunks);

    for (int i = 0; i < numChunks; ++i) {
        chunkFiles[i].open("chunk" + std::to_string(i) + ".bin", std::ios::binary);
        chunkFiles[i].rdbuf()->pubsetbuf(new char[BUFFER_SIZE], BUFFER_SIZE);
        int value;
        if (chunkFiles[i].read(reinterpret_cast<char*>(&value), sizeof(int))) {
            minHeap.push({value, i});
        }
    }

    std::ofstream output(outputFilePath, std::ios::binary);
    output.rdbuf()->pubsetbuf(new char[BUFFER_SIZE], BUFFER_SIZE);

    while (!minHeap.empty()) {
        auto top = minHeap.top();
        minHeap.pop();
        output.write(reinterpret_cast<const char*>(&top.first), sizeof(int));

        int value;
        if (chunkFiles[top.second].read(reinterpret_cast<char*>(&value), sizeof(int))) {
            minHeap.push({value, top.second});
        }
    }

    for (auto& file : chunkFiles) file.close();
}

void benchmark(const std::string &inputFilePath, const std::string &outputFilePath) {
    auto start_time = std::chrono::high_resolution_clock::now();

    std::ifstream file(inputFilePath, std::ios::binary);
    file.seekg(0, std::ios::end);
    std::size_t fileSize = file.tellg();
    int numChunks = (fileSize + CHUNK_SIZE - 1) / CHUNK_SIZE;
    file.close();

    std::vector<std::thread> sortThreads;
    for (int i = 0; i < numChunks; ++i) {
        sortThreads.emplace_back(sortChunk, inputFilePath, i);
    }

    for (auto& thread : sortThreads) {
        thread.join();
    }

    mergeChunks(outputFilePath, numChunks);

    auto end_time = std::chrono::high_resolution_clock::now();
    std::chrono::duration<double> elapsed = end_time - start_time;

    std::cout << "Sorting completed in " << elapsed.count() << " seconds.\n";
}

int main(int argc, char* argv[]) {
    if (argc != 3) {
        std::cerr << "Usage: " << argv[0] << " <input file path> <output file path>" << std::endl;
        return 1;
    }

    std::string inputFilePath = argv[1];
    std::string outputFilePath = argv[2];

    benchmark(inputFilePath, outputFilePath);

    return 0;
}

