import (
	"fmt"
	"log"
	"math/rand"
	"sync"
	"time"
)

type Command interface {
	Execute() string
}

type SetCommand struct {
	Key   string
	Value string
}

func (c *SetCommand) Execute() string {
	return fmt.Sprintf("Set %s to %s", c.Key, c.Value)
}

type Node struct {
	ID                int
	Peers             []*Node
	State             string
	CurrentTerm       int
	VotedFor          int
	LogEntries        []LogEntry
	CommitIndex       int
	LastApplied       int
	NextIndex         map[int]int
	MatchIndex        map[int]int
	ElectionTimeout   time.Duration
	HeartbeatInterval time.Duration
	LastHeartbeat     time.Time
	Failure           bool
	Mu                sync.Mutex
	CommitChan        chan Command
	VoteChan          chan Vote
	AppendLogChan     chan LogEntry
	HeartbeatChan     chan bool
}

type Vote struct {
	Term        int
	CandidateID int
	VoteGranted bool
}

type LogEntry struct {
	Term    int
	Command Command
}

func NewNode(id int) *Node {
	electionTimeout := time.Duration(rand.Intn(150)+150) * time.Millisecond
	heartbeatInterval := time.Duration(100) * time.Millisecond

	node := &Node{
		ID:                id,
		State:             "follower",
		CurrentTerm:       0,
		VotedFor:          -1,
		LogEntries:        []LogEntry{},
		NextIndex:         make(map[int]int),
		MatchIndex:        make(map[int]int),
		ElectionTimeout:   electionTimeout,
		HeartbeatInterval: heartbeatInterval,
		LastHeartbeat:     time.Now(),
		CommitChan:        make(chan Command, 10),
		VoteChan:          make(chan Vote, 10),
		AppendLogChan:     make(chan LogEntry, 10),
		HeartbeatChan:     make(chan bool, 10),
	}
	go node.run()
	return node
}

func (n *Node) run() {
	for {
		if n.Failure {
			time.Sleep(n.ElectionTimeout)
			continue
		}
		switch n.State {
		case "follower":
			n.runAsFollower()
		case "candidate":
			n.runAsCandidate()
		case "leader":
			n.runAsLeader()
		}
	}
}

func (n *Node) runAsFollower() {
	electionTimer := time.NewTimer(n.ElectionTimeout)
	defer electionTimer.Stop()

	for {
		select {
		case <-electionTimer.C:
			n.startElection()
		case vote := <-n.VoteChan:
			n.handleVote(vote)
		case entry := <-n.AppendLogChan:
			n.handleAppendLog(entry)
		case <-n.HeartbeatChan:
			electionTimer.Reset(n.ElectionTimeout)
		}
		if n.Failure {
			return
		}
	}
}

func (n *Node) startElection() {
	n.State = "candidate"
	n.CurrentTerm += 1
	n.VotedFor = n.ID
	votesReceived := 1

	for _, peer := range n.Peers {
		go n.requestVote(peer)
	}

	voteMajority := len(n.Peers)/2 + 1
	voteCounter := time.NewTimer(n.ElectionTimeout)
	defer voteCounter.Stop()

	for {
		select {
		case vote := <-n.VoteChan:
			if vote.VoteGranted {
				votesReceived++
				if votesReceived >= voteMajority {
					n.State = "leader"
					n.initializeLeader()
					return
				}
			}
		case <-voteCounter.C:
			n.State = "follower"
			return
		}
		if n.Failure {
			return
		}
	}
}

func (n *Node) requestVote(peer *Node) {
	voteGranted := false
	if peer.VotedFor == -1 || peer.VotedFor == n.ID {
		voteGranted = true
	}
	peer.VoteChan <- Vote{
		Term:        n.CurrentTerm,
		CandidateID: n.ID,
		VoteGranted: voteGranted,
	}
}

func (n *Node) runAsCandidate() {
	n.startElection()
}

func (n *Node) handleVote(vote Vote) {
	n.Mu.Lock()
	defer n.Mu.Unlock()
	if vote.Term > n.CurrentTerm {
		n.CurrentTerm = vote.Term
		n.State = "follower"
		n.VotedFor = -1
	}
}

func (n *Node) handleAppendLog(entry LogEntry) {
	n.Mu.Lock()
	defer n.Mu.Unlock()
	n.LogEntries = append(n.LogEntries, entry)
	if len(n.LogEntries) >= n.CommitIndex+1 {
		n.CommitIndex++
		fmt.Println(entry.Command.Execute())
	}
	n.LastHeartbeat = time.Now()
}

func (n *Node) runAsLeader() {
	heartbeatTimer := time.NewTicker(n.HeartbeatInterval)
	defer heartbeatTimer.Stop()

	for {
		select {
		case command := <-n.CommitChan:
			n.appendEntry(command)
		case <-heartbeatTimer.C:
			n.sendHeartbeat()
		}
		if n.Failure {
			return
		}
	}
}

func (n *Node) initializeLeader() {
	n.Mu.Lock()
	defer n.Mu.Unlock()
	for _, peer := range n.Peers {
		n.NextIndex[peer.ID] = len(n.LogEntries)
		n.MatchIndex[peer.ID] = 0
	}
}

func (n *Node) appendEntry(command Command) {
	n.Mu.Lock()
	entry := LogEntry{
		Term:    n.CurrentTerm,
		Command: command,
	}
	n.LogEntries = append(n.LogEntries, entry)
	n.Mu.Unlock()
	fmt.Printf("Node %d appended entry: %s\n", n.ID, command.Execute())
	for _, peer := range n.Peers {
		go func(peer *Node) {
			peer.AppendLogChan <- entry
		}(peer)
	}
}

func (n *Node) sendHeartbeat() {
	fmt.Printf("Node %d sending heartbeat\n", n.ID)
	for _, peer := range n.Peers {
		go func(peer *Node) {
			peer.HeartbeatChan <- true
		}(peer)
	}
}

func main() {
	nodeCount := 5
	nodes := make([]*Node, nodeCount)
	for i := 0; i < nodeCount; i++ {
		nodes[i] = NewNode(i)
	}
	for i := 0; i < nodeCount; i++ {
		var peers []*Node
		for j := 0; j < nodeCount; j++ {
			if i != j {
				peers = append(peers, nodes[j])
			}
		}
		nodes[i].Peers = peers
	}

	go func() {
		for {
			time.Sleep(3 * time.Second)
			node := nodes[rand.Intn(len(nodes))]
			command := &SetCommand{Key: fmt.Sprintf("key-%d", rand.Intn(1000)), Value: "value"}
			if node.State == "leader" {
