import hashlib
import hmac
from flask import Flask, request, jsonify, abort
from functools import wraps
from typing import List

app = Flask(__name__)

# Constants for LSH
NUM_HASHES = 128
BANDS = 8
ROWS_PER_BAND = NUM_HASHES // BANDS

# Secret key for HMAC comparison (should be kept secret)
SECRET_KEY = b"YOUR_SECRET_KEY"

# Sample data representing the dataset of vectors
dataset = [
    np.random.rand(128).tolist(),
    np.random.rand(128).tolist(),
    np.random.rand(128).tolist()
]

# Function to perform constant-time hashing for LSH
def lsh_hash(vector: List[float], index: int) -> str:
    hash_input = np.array(vector) * (index + 1)  # Use index for seed-like variation
    return hashlib.sha256(hash_input.tobytes()).hexdigest()

# Function for constant-time comparison to prevent timing attacks
def constant_time_compare(val1, val2):
    return hmac.compare_digest(val1.encode('utf-8'), val2.encode('utf-8'))

# Rate limiter decorator
def rate_limiter(max_calls: int, period: float):
    call_counts = {}

    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            time_block = int(time.time() // period)
            requester = request.remote_addr
            if requester not in call_counts:
                call_counts[requester] = {}
            if time_block not in call_counts[requester]:
                call_counts[requester][time_block] = 0

            if call_counts[requester][time_block] >= max_calls:
                abort(429, description="Rate limit exceeded.")

            call_counts[requester][time_block] += 1
            return func(*args, **kwargs)

        return wrapper
    return decorator

@app.route('/nearest_neighbor', methods=['POST'])
@rate_limiter(max_calls=5, period=60)
def nearest_neighbor():
    # Input validation
    content = request.json
    if 'vector' not in content or not isinstance(content['vector'], list) or len(content['vector']) != 128:
        return jsonify({"error": "Invalid input"}), 400

    vector = content['vector']
    if not all(isinstance(x, float) for x in vector):
        return jsonify({"error": "Invalid vector input"}), 400

    # Hash input vector
    hashed_input = [lsh_hash(vector, i) for i in range(NUM_HASHES)]

    # Find nearest neighbors by hashing the dataset
    nearest_neighbors = []
    for data in dataset:
        hashed_data = [lsh_hash(data, i) for i in range(NUM_HASHES)]
        matches = sum(constant_time_compare(h, hi) for h, hi in zip(hashed_data, hashed_input))
        if matches >= ROWS_PER_BAND:
            nearest_neighbors.append(data)

    return jsonify(nearest_neighbors)

if __name__ == '__main__':
    app.run(debug=True)
