namespace geometry {
    std::vector<Point> ConvexHull::compute(const std::vector<Point>& points) {
        if (points.size() < 3) return points;

        std::vector<Point> sortedPoints = points;
        std::sort(sortedPoints.begin(), sortedPoints.end());

        std::vector<Point> hull;

        // Lower hull
        for (const auto& p : sortedPoints) {
            while (hull.size() >= 2) {
                auto q = hull[hull.size() - 2];
                auto r = hull[hull.size() - 1];
                if ((r.first - q.first) * (p.second - q.second) <= (r.second - q.second) * (p.first - q.first)) {
                    hull.pop_back();
                } else {
                    break;
                }
            }
            hull.push_back(p);
        }

        // Upper hull
        size_t t = hull.size() + 1;
        for (auto it = sortedPoints.rbegin(); it != sortedPoints.rend(); ++it) {
            while (hull.size() >= t) {
                auto q = hull[hull.size() - 2];
                auto r = hull[hull.size() - 1];
                if ((r.first - q.first) * (it->second - q.second) <= (r.second - q.second) * (it->first - q.first)) {
                    hull.pop_back();
                } else {
                    break;
                }
            }
            hull.push_back(*it);
        }

        hull.pop_back();
        return hull;
    }
}

