class PaymentController {

    private static final String HMAC_SHA256 = "HmacSHA256";

    @PostMapping("/tokenize")
    public Map<String, String> tokenizeCard(@Valid @RequestBody CreditCard card) {
        // Assume an external PCI DSS-compliant service for tokenization
        String token = ""; // Example: token = paymentService.tokenize(card);
        return Map.of("token", token);
    }

    @PostMapping("/webhook")
    public String webhookEndpoint(@RequestBody Map<String, String> data, @RequestHeader("X-Hmac-Signature") String signature) {
        if (validateHmacSignature(data.toString(), signature)) {
            // Process the webhook data
            return "Webhook processed successfully";
        } else {
            throw new SecurityException("Invalid webhook signature");
        }
    }

    private boolean validateHmacSignature(String data, String clientSignature) {
        try {
            String secret = "secret-key"; // The secret key should be fetched in a secure manner
            Mac sha256Hmac = Mac.getInstance(HMAC_SHA256);
            SecretKeySpec secretKey = new SecretKeySpec(secret.getBytes(StandardCharsets.UTF_8), HMAC_SHA256);
            sha256Hmac.init(secretKey);
            byte[] signedData = sha256Hmac.doFinal(data.getBytes(StandardCharsets.UTF_8));
            String computedSignature = Base64.getEncoder().encodeToString(signedData);

            return computedSignature.equals(clientSignature);
        } catch (Exception e) {
            throw new RuntimeException("Failed to calculate HMAC", e);
        }
    }
}

