	wg       *sync.WaitGroup
}

type Job struct {
	input    string
	output   string
	bitrate  string
	resolution string
}

func Transcode(ctx context.Context, job Job) error {
	cmd := exec.CommandContext(ctx, "ffmpeg",
		"-hwaccel", "cuda",
		"-i", job.input,
		"-c:v", "h264_nvenc",
		"-b:v", job.bitrate,
		"-s", job.resolution,
		"-f", "mp4",
		"-y", job.output,
	)
	var stderr bytes.Buffer
	cmd.Stderr = &stderr
	if err := cmd.Run(); err != nil {
		return fmt.Errorf("ffmpeg error: %v, details: %s", err, stderr.String())
	}
	return nil
}

func (w *Worker) Start(ctx context.Context) {
	defer w.wg.Done()
	for job := range w.jobQueue {
		select {
		case <-ctx.Done():
			log.Printf("Worker %d context done", w.id)
			return
		default:
			if err := Transcode(ctx, job); err != nil {
				log.Printf("Worker %d failed to transcode: %v", w.id, err)
			} else {
				log.Printf("Worker %d successfully transcoded %s to %s", w.id, job.input, job.output)
			}
		}
	}
}

func CreateWorkerPool(numWorkers int, wg *sync.WaitGroup) ([]Worker, chan Job) {
	jobQueue := make(chan Job, numWorkers)
	workers := make([]Worker, numWorkers)
	for i := 0; i < numWorkers; i++ {
		workers[i] = Worker{
			id:       i,
			jobQueue: jobQueue,
			wg:       wg,
		}
	}
	return workers, jobQueue
}

func main() {
	wg := &sync.WaitGroup{}
	workers, jobQueue := CreateWorkerPool(maxWorkers, wg)

	ctx, cancel := context.WithTimeout(context.Background(), timeoutDuration)
	defer cancel()

	wg.Add(len(workers))
	for _, worker := range workers {
		go worker.Start(ctx)
	}

	jobs := []Job{
		{input: "input1.mp4", output: "output_720p1.mp4", bitrate: "1500k", resolution: "1280x720"},
		{input: "input2.mp4", output: "output_720p2.mp4", bitrate: "1500k", resolution: "1280x720"},
	}

	for _, job := range jobs {
		jobQueue <- job
	}
	close(jobQueue)
	wg.Wait()
}
